function getCollectedPeriod(isoTs, cadenza) {
  const d = new Date(isoTs || new Date().toISOString());
  const pad = n => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  const doy = Math.floor((d - new Date(Date.UTC(yyyy,0,1))) / 86400000);
  const week = pad(Math.ceil((doy + new Date(Date.UTC(yyyy,0,1)).getUTCDay() + 1) / 7));
  switch((cadenza||'').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${week}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}
const now = new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(now, 'monthly');
const meta = $('CONAB Extract Levantamento URL').item.json;
const rawHtml = String($json.data ?? $json.body ?? '').trim();
if (!rawHtml) throw new Error('CONAB: levantamento page HTML vuota');

const pdfMatch = rawHtml.match(/href="(https?:\/\/[^"]+\.pdf)"/i);
const xlsMatch = rawHtml.match(/href="(https?:\/\/[^"]+\.xls[x]?)"/i);

if (!pdfMatch) throw new Error('CONAB: PDF non trovato nella pagina levantamento');
if (!xlsMatch) throw new Error('CONAB: XLS non trovato nella pagina levantamento');

const pdfUrl  = pdfMatch[1];
const tableUrl = xlsMatch[1];

const publishedDateRaw = null; // non estratta dal nuovo gov.br

const releaseKey = meta.season && meta.survey_number
  ? `${meta.season}-lev-${meta.survey_number}`
  : pdfUrl;

return [{
  json: {
    source: 'CONAB_CAFE_SAFRA',
    source_format: 'html_index+xls+pdf',
    country: 'BR',
    macroarea: 'colture',
    collected_at: now,
    collected_period: _collectedPeriod,
        index_url: 'https://www.gov.br/conab/pt-br/atuacao/informacoes-agropecuarias/safras/safra-de-cafe',
    source_url: 'https://www.gov.br/conab/pt-br/atuacao/informacoes-agropecuarias/safras/safra-de-cafe',
    levantamento_url: meta.levantamento_url,
    release_title: meta.release_title,
    release_key: releaseKey,
    survey_number: meta.survey_number,
    season: meta.season,
    published_date_raw: publishedDateRaw,
    pdf_url: pdfUrl,
    table_url: tableUrl
  }
}];

function getCollectedPeriod(isoTs, cadenza) {
  const d = new Date(isoTs || new Date().toISOString());
  const pad = n => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  const doy = Math.floor((d - new Date(Date.UTC(yyyy,0,1))) / 86400000);
  const week = pad(Math.ceil((doy + new Date(Date.UTC(yyyy,0,1)).getUTCDay() + 1) / 7));
  switch((cadenza||'').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${week}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}
const now = new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(now, 'monthly');
const meta = $('CONAB Parse Latest Release').item.json;
const extractedRows = $input.all()
  .map((item) => Array.isArray(item.json.row) ? item.json.row : [])
  .filter((row) => row.some((value) => String(value ?? '').trim() !== ''));

if (!extractedRows.length) throw new Error('CONAB table extract returned no rows');

function normalizeText(value) {
  return String(value ?? '').trim();
}

function normalizeNumber(value, decimals = 4) {
  if (value === null || value === undefined) return null;
  if (typeof value === 'number') {
    if (!Number.isFinite(value)) return null;
    return Number(value.toFixed(decimals));
  }
  const text = normalizeText(value);
  if (!text || text === '-' || text === '--' || text === '…' || text === '...') return null;
  const numeric = Number(text.replace(/\./g, '').replace(',', '.'));
  if (Number.isNaN(numeric)) return null;
  return Number(numeric.toFixed(decimals));
}

const normalizedRows = extractedRows.map((row) => row.map((cell) => normalizeText(cell).toLowerCase()));
const headerIndex = normalizedRows.findIndex((row) => row.includes('(d)') && row.includes('(f)'));
if (headerIndex === -1) throw new Error('CONAB table markers (d) and (f) not found');
const yieldColumn = normalizedRows[headerIndex].findIndex((value) => value === '(d)');
const productionColumn = normalizedRows[headerIndex].findIndex((value) => value === '(f)');
const regionColumn = 0;

const ufMap = {
  MG: 'Minas Gerais', ES: 'Espírito Santo', SP: 'São Paulo', PR: 'Paraná', BA: 'Bahia', RO: 'Rondônia', GO: 'Goiás',
  MT: 'Mato Grosso', RJ: 'Rio de Janeiro', PE: 'Pernambuco', AC: 'Acre', CE: 'Ceará', PA: 'Pará', AM: 'Amazonas'
};
const focusUfs = ['MG', 'ES', 'BA', 'RO'];

const stateRows = extractedRows
  .slice(headerIndex + 1)
  .map((row) => ({
    uf: normalizeText(row[regionColumn]).toUpperCase(),
    production_raw: normalizeNumber(row[productionColumn], 4),
    yield_raw: normalizeNumber(row[yieldColumn], 4)
  }))
  .filter((row) => /^[A-Z]{2}$/.test(row.uf))
  .map((row) => ({
    uf: row.uf,
    state: ufMap[row.uf] || row.uf,
    production_thousand_60kg_bags: row.production_raw,
    yield_60kg_bags_per_ha: row.yield_raw,
    production_mt: row.production_raw === null ? null : Number((row.production_raw * 60).toFixed(4)),
    yield_kgha: row.yield_raw === null ? null : Number((row.yield_raw * 60).toFixed(4))
  }))
  .filter((row) => row.production_mt !== null || row.yield_kgha !== null);

if (!stateRows.length) throw new Error('CONAB table produced no state rows');

const validProductionRows = stateRows.filter((row) => row.production_mt !== null);
const totalProductionMt = validProductionRows.reduce((sum, row) => sum + row.production_mt, 0);
const topStatesByProduction = [...validProductionRows]
  .sort((a, b) => (b.production_mt ?? -Infinity) - (a.production_mt ?? -Infinity))
  .slice(0, 10)
  .map((row) => ({
    uf: row.uf,
    state: row.state,
    production_mt: row.production_mt,
    share_of_total_pct: totalProductionMt ? Number(((row.production_mt / totalProductionMt) * 100).toFixed(4)) : null,
    yield_kgha: row.yield_kgha
  }));
const focusStates = focusUfs.map((uf) => {
  const row = stateRows.find((entry) => entry.uf === uf) || { uf, state: ufMap[uf] || uf, production_mt: null, yield_kgha: null, production_thousand_60kg_bags: null, yield_60kg_bags_per_ha: null };
  return {
    ...row,
    share_of_total_pct: row.production_mt !== null && totalProductionMt ? Number(((row.production_mt / totalProductionMt) * 100).toFixed(4)) : null
  };
});
const focusProductionMt = focusStates.reduce((sum, row) => sum + (row.production_mt ?? 0), 0);
const focusSharePct = totalProductionMt ? Number(((focusProductionMt / totalProductionMt) * 100).toFixed(4)) : null;
const bestYieldState = [...stateRows].filter((row) => row.yield_kgha !== null).sort((a, b) => b.yield_kgha - a.yield_kgha)[0] || null;
const lowestYieldState = [...stateRows].filter((row) => row.yield_kgha !== null).sort((a, b) => a.yield_kgha - b.yield_kgha)[0] || null;

return [{
  json: {
    ...meta,
    source_format: 'html_index+xls',
    country: 'BR',
    macroarea: 'colture',
    dataset: 'CONAB_CAFE_BULLETIN',
    collected_at: now,
    collected_period: _collectedPeriod,
        states_covered: stateRows.length,
    units: {
      production_raw: 'thousand_60kg_bags',
      production_normalized: 'metric_tons',
      yield_raw: '60kg_bags_per_ha',
      yield_normalized: 'kg_per_ha'
    },
    national_snapshot: {
      total_production_mt: Number(totalProductionMt.toFixed(4)),
      focus_states_total_production_mt: Number(focusProductionMt.toFixed(4)),
      focus_states_share_pct: focusSharePct,
      best_yield_state: bestYieldState ? { uf: bestYieldState.uf, state: bestYieldState.state, yield_kgha: bestYieldState.yield_kgha } : null,
      lowest_yield_state: lowestYieldState ? { uf: lowestYieldState.uf, state: lowestYieldState.state, yield_kgha: lowestYieldState.yield_kgha } : null
    },
    focus_states: focusStates,
    top_states_by_production: topStatesByProduction,
    all_states: stateRows
  }
}];

const rawText = ($json.text || '').trim();
const cleaned = rawText.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```$/i,'').trim();
const parsed = JSON.parse(cleaned || '{}');
const base = $('CONAB Parse Table').item.json;
const pdfSource = $('CONAB Extract PDF').item.json;
const pdfText = String(pdfSource.text ?? pdfSource.content ?? pdfSource.data ?? JSON.stringify(pdfSource)).replace(/\s+/g, ' ').trim();
const excerpt = pdfText.slice(0, 3000);
const pdfExcerpt = pdfText.slice(0, 6000);
const embedText = [parsed.summary_en || '', ...(Array.isArray(parsed.signals) ? parsed.signals : []), excerpt.slice(0, 1200)].filter(Boolean).join(' ');

return [{
  json: {
    ...base,
    pdf_excerpt: pdfExcerpt,
    source_format: 'html_index+xls+pdf',
    source_url: base.source_url || base.index_url || base.levantamento_url || base.pdf_url || null,
    movement_label: parsed.movement_label || 'mixed',
signals: Array.isArray(parsed.signals) ? parsed.signals : [],
    summary_en: parsed.summary_en || '',
    report_text_excerpt: excerpt,
    embed_text: embedText
  }
}];

// Calcola collected_period da collected_at + cadenza
function getCollectedPeriod(collectedAt, cadenza) {
  const d = new Date(collectedAt || new Date().toISOString());
  const pad = (n) => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  // ISO week number
  const startOfYear = new Date(Date.UTC(yyyy, 0, 1));
  const weekNo = pad(Math.ceil(((d - startOfYear) / 86400000 + startOfYear.getUTCDay() + 1) / 7));
  switch((cadenza || '').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${weekNo}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}

const _cadenza = 'monthly';
const _collectedAt = now || new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(_collectedAt, _cadenza);
const meta = $('CONAB Parse Signals').item.json;
const vector = $json.data[0].embedding;
const key = meta.release_key || meta.pdf_url || meta.release_title || '';
let hash = 0;
for (let i = 0; i < key.length; i++) {
  hash = ((hash << 5) - hash) + key.charCodeAt(i);
  hash |= 0;
}
const pointId = Math.abs(hash);

return [{
  json: {
    points: [{
      id: pointId,
      vector,
      payload: {
        source: meta.source,
        country: meta.country,
        macroarea: meta.macroarea,
        collected_at: meta.collected_at,
        release_title: meta.release_title,
        survey_number: meta.survey_number,
        season: meta.season,
        published_date_raw: meta.published_date_raw,
        pdf_url: meta.pdf_url,
        table_url: meta.table_url,
        movement_label: meta.movement_label,
summary_en: meta.summary_en,
        signals: meta.signals
      }
    }]
  }
}];

const now = new Date().toISOString();
const meta = $('CONAB Parse Signals').item.json;

return [{
  json: {
    source: 'CONAB_CAFE_SAFRA',
    country: 'BR',
    macroarea: 'colture',
    cadenza: 'weekly',
    run_date: now,
    status: 'done',
    completed_at: now,
    survey_number: meta.survey_number || null,
    season: meta.season || null,
  },
}];

const html = String($json.data ?? $json.body ?? '');
if (!html) throw new Error('CONAB: index page HTML vuota');

const links = [...html.matchAll(/href="(https:\/\/www\.gov\.br\/conab\/pt-br\/atuacao\/informacoes-agropecuarias\/safras\/safra-de-cafe\/[^"]*levantamento[^"]*\/[^"]*)"/gi)];
if (!links.length) throw new Error('CONAB: nessun link levantamento trovato nella index page');

const levUrl = links[0][1];

const urlMatch = levUrl.match(/\/(\d+)[oa][-]levantamento-de-cafe-safra-(\d{4})\//i);
const surveyNumber = urlMatch ? parseInt(urlMatch[1]) : null;
const season = urlMatch ? urlMatch[2] : null;
const releaseTitle = surveyNumber && season ? `${surveyNumber}º Levantamento Café - Safra ${season}` : levUrl;

return [{ json: { levantamento_url: levUrl, survey_number: surveyNumber, season, release_title: releaseTitle } }];

const item = $input.first();
const err = item.json?.error ?? item.error?.message ?? '';
const statusCode = item.json?.statusCode ?? item.json?.status ?? 0;
if (err || statusCode >= 400) {
  return [{ json: {
    _api_skip: true,
    source: '03_CONAB',
    country: 'BR',
    status: 'skipped_api_error',
    reason: `API unavailable: ${err || 'HTTP ' + statusCode}`,
    run_date: new Date().toISOString(),
    completed_at: new Date().toISOString()
  } }];
}
return [{ json: item.json }];
